  ('lipidmanagement', 'Lipidmanagement / Erhöhte Triglyceride', 'Lipid Management / Elevated Triglycerides', 'triglyceride, cholesterin, lipide, blutfette, dyslipidämie', 'triglycerides, cholesterol, lipids, blood lipids, dyslipidemia', 'Herzgesundheit', 'Lipidstoffwechsel', 'marine-phospholipide, fischoel', '✅✅ Krillöl/Marine Phospholipide bei erhöhten Triglyceriden - Meta-Analyse 2023 (PMID 38039646)', '-', '-', '✅✅ Huang et al. 2023 Meta-Analyse (14 RCTs, n=1458): Signifikante Reduktion TC (P=0,01), LDL-C (P=0,006), Triglyceride (P=0,0005). 1-4g/Tag Krillöl.', 'Krill oil significantly reduces TC, LDL, TG (PMID 38039646)', 'Bei stark erhöhten Werten', 'Ärztliche Kontrolle bei Dyslipidämie'),
  ('pms-dysmenorrhoe', 'PMS / Dysmenorrhoe', 'PMS / Dysmenorrhea', 'pms, menstruation, regelschmerzen, dysmenorrhoe, prämenstruell', 'pms, menstruation, period pain, dysmenorrhea, premenstrual', 'Frauengesundheit', 'Menstruationsbeschwerden', 'marine-phospholipide', '✅ Krillöl bei PMS/Dysmenorrhoe - Sampalis 2003 (PMID 12777162)', '-', '-', '✅ Sampalis 2003 (n=70): 2g/Tag Krillöl × 3 Monate → Signifikante Verbesserung (P<0,001): Reizbarkeit -47%, Depression -40%, Bauchschmerzen -33%, reduzierter Schmerzmittelverbrauch (P<0,03 vs. Fischöl)', 'Neptune Krill Oil significantly improved PMS symptoms (PMID 12777162)', 'Bei schweren Beschwerden', 'Gynäkologische Abklärung bei Dysmenorrhoe'),
  ('narbenbehandlung', 'Narbenbehandlung (topisch)', 'Scar Treatment (topical)', 'narben, narbenbehandlung, aknenarben, operationsnarben, keloid', 'scars, scar treatment, acne scars, surgical scars, keloid', 'Hautgesundheit', 'Narben und Wundheilung', 'hagebuttenkernoel', '✅ Hagebuttenkernöl topisch für Narben - Valerón-Almazán 2015', '-', '-', '✅ Valerón-Almazán 2015 (n=108): Reines Hagebuttenkernöl 2x täglich × 6 Wochen → Signifikante Verbesserung bei Erythem, Verfärbung, Atrophie postoperativer Narben.', 'Rosehip oil improved postoperative scars (DOI: 10.4236/jcdsa.2015.53019)', 'Bei tiefen/hypertrophen Narben', 'Dermatologische Beurteilung'),
  ('dehnungsstreifen', 'Dehnungsstreifen / Striae', 'Stretch Marks / Striae', 'dehnungsstreifen, schwangerschaftsstreifen, striae, striae gravidarum', 'stretch marks, striae, pregnancy stretch marks', 'Hautgesundheit', 'Bindegewebe', 'hagebuttenkernoel', '⚠️ Hagebuttenkernöl in Kombinationsprodukten für Dehnungsstreifen - García Hernández 2013 (PMID 23237514)', '-', '-', '⚠️ García Hernández 2013: Kombination mit Hydroxyprolisilane-C + Centella asiatica → 5,6% vs. 35% neue Striae (P=0,031). JEDOCH: Kombinationsprodukt, nicht Hagebuttenkernöl allein!', 'Combination product with rosehip reduced stretch marks (PMID 23237514)', 'Nein', '-'),
