  ('lipidprofil', 'Lipidprofil / Cholesterin', 'Lipid Profile / Cholesterol', 'Cholesterin, LDL, Triglyceride, Lipide, Herz-Kreislauf', 'cholesterol, LDL, triglycerides, lipids, cardiovascular', 'Stoffwechsel', 'Lipidmetabolismus', 'xylooligosaccharide', 'XOS 2,7-4 g/Tag (supportiv)', '-', '-', '⭐ MODERATE EVIDENZ! Sheu 2008: signifikante Reduktion Gesamtcholesterin, LDL, oxLDL, ApoB bei 4 g/Tag. Na & Kim 2007: bereits 2,7 g/Tag über 2 Wochen zeigte Effekte bei jungen Frauen.', 'Moderate evidence for cholesterol reduction. Multiple studies show LDL lowering.', 'Nein', '-'),
  ('fodmap-ibs', 'FODMAP-Sensitivität / IBS', 'FODMAP Sensitivity / IBS', 'FODMAP, Reizdarm, IBS, Blähungen, empfindlicher Magen', 'FODMAP, irritable bowel, IBS, bloating, sensitive stomach', 'Gastroenterologie', 'Funktionell', 'xylooligosaccharide', '⭐ XOS bevorzugt bei FODMAP-Sensitivität!', 'fructooligosaccharide, inulin', '-', '⭐ XOS = BESTE WAHL bei FODMAP! Nicht offiziell als FODMAP klassifiziert. Kein Gas bei Fermentation (anders als FOS/Inulin). Niedrige Dosis (1,4 g) minimiert GI-Symptome. Laufende Studie zu XOS bei IBS.', 'XOS best choice for FODMAP-sensitive. No gas production. Low dose minimizes symptoms.', 'Bei IBS', 'Gastroenterologische Betreuung'),
  ('immunmodulation-xos', 'Immunmodulation', 'Immune Modulation', 'Immunsystem, Entzündungen, Inflammation, Abwehrkräfte', 'immune system, inflammation, defense', 'Immunologie', 'Immunsystem', 'xylooligosaccharide, inulin', 'INU-XOS Kombination (3g Inulin + 1g XOS)', '-', '-', '⚠️ XOS ALLEIN nur präbiotisch, NICHT immunmodulatorisch! ABER: INU-XOS Kombination (3g Inulin + 1g XOS) zeigt immunmodulatorische Effekte: IL-1β↓, LPS↓. Tierstudien: IFN-γ↓, IL-18↓.', 'XOS alone only prebiotic. INU-XOS combination shows immune effects. Preclinical data promising.', 'Nein', '-'),
  ('knochengesundheit-xos', 'Knochengesundheit', 'Bone Health', 'Knochen, Osteoporose, Calciumabsorption, Knochendichte', 'bone, osteoporosis, calcium absorption, bone density', 'Stoffwechsel', 'Knochenmetabolismus', 'xylooligosaccharide, calcium', 'XOS + Calcium (supportiv)', '-', '-', '⚠️ NUR PRÄKLINISCHE DATEN! Mausstudie 2020: 4% XOS → erhöhte Knochenmineraldichte, verbesserte Bruchfestigkeit, Upregulation TRPV6/NCX1. KEINE Humanstudien!', 'ONLY preclinical data. Mouse study showed improved bone density. No human studies.', 'Nein', '-'),
  ('darmgesundheit-imo', 'Darmgesundheit / Präbiotik', 'Gut Health / Prebiotic', 'Darmgesundheit, präbiotisch, Mikrobiom, Bifidobakterien', 'gut health, prebiotic, microbiome, bifidobacteria', 'Verdauung', 'Mikrobiom', '⚠️ NICHT: isomaltooligosaccharide', '❌ IMO NICHT EMPFEHLEN! Stattdessen: 1. XOS, 2. GOS, 3. FOS, 4. Inulin', 'isomaltooligosaccharide', '-', '❌ IMO ist KEIN echtes Präbiotikum! FDA/EFSA abgelehnt. 70-90% werden im Dünndarm verdaut. Nur 10-50% erreichen Kolon. Bouhnik 2004: KEIN bifidogener Effekt bei Europäern!', 'IMO is NOT a true prebiotic. 70-90% digested. FDA rejected fiber status. Use XOS/GOS/FOS/Inulin instead.', 'Nein', '-'),
  ('zuckerersatz-imo', 'Zuckerersatz / Süßungsmittel', 'Sugar Replacement / Sweetener', 'Zuckerersatz, kalorienarm, Süßungsmittel, Sirup', 'sugar replacement, low calorie, sweetener, syrup', 'Ernährung', 'Süßungsmittel', 'isomaltooligosaccharide (mit Einschränkungen!)', 'IMO als Süßungsmittel (⚠️ aber NICHT kalorienarm oder blutzuckerneutral!)', '-', '-', '⚠️ EINGESCHRÄNKT! IMO hat ~50-60% Süßkraft von Zucker, ABER: 2,7-3,3 kcal/g (nur 17-32% weniger als Zucker!), ERHÖHT Blutzucker! Für Diabetiker NICHT empfehlen!', 'IMO is sweetener but NOT low-calorie (2.7-3.3 kcal/g) and RAISES blood sugar. Not for diabetics!', 'Bei Diabetes', 'Diabetologische Beratung'),
  ('obstipation-imo', 'Obstipation / Verstopfung', 'Constipation', 'Verstopfung, Obstipation, Stuhlfrequenz', 'constipation, stool frequency', 'Verdauung', 'Stuhlgang', '⚠️ NICHT: isomaltooligosaccharide', '❌ IMO NICHT EMPFEHLEN! EFSA Claim ID 800 ABGELEHNT. Stattdessen: XOS, GOS, Inulin.', 'isomaltooligosaccharide', '-', '❌ EFSA-CLAIM ABGELEHNT! "Erhöhung der täglichen Stuhlfrequenz" nicht belegt. FDA: Keine Verbesserung der Laxation nachweisbar.', 'EFSA rejected claim. FDA: No laxation benefit proven. Use proven prebiotics instead.', 'Bei chronischer Obstipation', 'Abklärung organischer Ursachen'),
  ('blutzucker-imo', 'Blutzuckerregulation', 'Blood Sugar Regulation', 'Blutzucker, glykämischer Index, Diabetes, Insulin', 'blood sugar, glycemic index, diabetes, insulin', 'Stoffwechsel', 'Glukosemetabolismus', '❌ NICHT: isomaltooligosaccharide', '❌ IMO NICHT EMPFEHLEN für Blutzuckerkontrolle!', 'isomaltooligosaccharide', '-', '❌ EFSA-CLAIM ABGELEHNT! ID 798 "Reduktion postprandialer glykämischer Antwort" NICHT belegt. Gourineni 2018: KEIN Unterschied zu Dextrose! IMO ERHÖHT Blutzucker!', 'EFSA rejected glycemic claim. Study shows NO difference from dextrose. IMO RAISES blood sugar!', 'Bei Diabetes', 'Diabetologische Beratung'),
  ('kalorienreduktion', 'Kalorienreduktion / Gewicht', 'Calorie Reduction / Weight', 'kalorienarm, Diät, Gewichtsabnahme, Low-Calorie', 'low calorie, diet, weight loss', 'Stoffwechsel', 'Energiebilanz', '⚠️ BEDINGT: isomaltooligosaccharide', 'IMO nur bedingt (⚠️ 2,7-3,3 kcal/g = nur 17-32% weniger als Zucker!)', '-', '-', '⚠️ MARKETING vs. REALITÄT! IMO wird als "Low-Calorie" beworben, liefert aber 2,7-3,3 kcal/g (Zucker: 4 kcal/g). Nur 17-32% Kalorienersparnis! Für echte Kalorienreduktion: Erythritol (0 kcal), Stevia, Allulose.', 'Marketing claims "low calorie" but IMO provides 2.7-3.3 kcal/g. Only 17-32% calorie reduction vs sugar.', 'Nein', '-'),
  ('epa-vegan-sda', '⭐ EPA-Versorgung (vegan/SDA)', 'EPA Supply (Vegan/SDA)', 'EPA, Eicosapentaensäure, vegan, Omega-3, pflanzlich', 'EPA, eicosapentaenoic acid, vegan, omega-3, plant-based', 'Fettsäuren', 'Omega-3-Versorgung', 'ahiflower-oel, echiumoel', '1. Ahiflower (17-21% SDA - höchster!) 2. Echiumöl (10-15% SDA + GLA)', '-', '-', '⭐ SDA-ÖLE = BESTE VEGANE EPA-VORSTUFE! SDA wird 3-5× effizienter zu EPA konvertiert als ALA (30% vs. 5-10%). RCT: Ahiflower erhöht EPA 3× mehr als Leinsamenöl. ⚠️ ERHÖHT NICHT DHA - Algenöl zusätzlich nötig!', 'SDA oils are the best vegan EPA precursor. SDA→EPA: 30% vs ALA→EPA: 5-10%. Does NOT raise DHA!', 'Für vegane/vegetarische EPA-Versorgung', '⚠️ DHA separat via Algenöl!'),
  ('antiinflammatorisch-sda', 'Entzündungshemmung (SDA-Öle)', 'Anti-inflammatory (SDA Oils)', 'Entzündung, Inflammation, anti-inflammatorisch', 'inflammation, anti-inflammatory', 'Immunsystem', 'Entzündungsmodulation', 'ahiflower-oel, echiumoel', '1. Ahiflower (IL-10 +45% in RCT!) 2. Echiumöl', '-', '-', 'RCT Lefort 2017: Ahiflower erhöhte IL-10 (anti-inflammatorisches Zytokin) um 45% in der höchsten Dosisgruppe. EPA-Metabolite (Resolvine, Protektine) sind entzündungshemmend.', 'Ahiflower RCT: IL-10 +45%. EPA metabolites are anti-inflammatory.', 'Bei chronischen Entzündungen als Ergänzung', 'Lefort 2017 (PMID: 28287415)'),
  ('hautgesundheit-gla-sda', 'Hautgesundheit (GLA+SDA)', 'Skin Health (GLA+SDA)', 'Haut, Hautbarriere, trockene Haut, Ekzem', 'skin, skin barrier, dry skin, eczema', 'Haut', 'Hautfunktion', 'echiumoel', '⭐ Echiumöl (10-11% GLA + SDA!)', '-', 'ahiflower-oel (weniger GLA)', 'Echiumöl enthält sowohl GLA (10-11%) als auch SDA (10-15%). GLA ist bekannt für Hautbarriere-Unterstützung (ähnlich Nachtkerzen-/Borretschöl). Vorteil: Zusätzlich SDA für EPA!', 'Echium oil contains GLA (skin barrier) + SDA (EPA precursor).', 'Bei Hautproblemen mit GLA-Bedarf', 'Echiumöl Vorteil: GLA + SDA kombiniert!'),
  ('lipidprofil-sda', 'Lipidprofil/Triglyzeride (SDA-Öle)', 'Lipid Profile (SDA Oils)', 'Cholesterin, Triglyzeride, Lipide', 'cholesterol, triglycerides, lipids', 'Herz-Kreislauf', 'Lipidstoffwechsel', 'echiumoel, ahiflower-oel', '1. Echiumöl (mehr klinische Evidenz) 2. Ahiflower', '-', '-', 'RCT Kuhnt 2014: Echiumöl (17g/Tag, 8 Wochen) senkte Serum-Cholesterin, LDL, oxLDL signifikant. Triglyzeride -9%. Surette 2004: Triglyzeride -21% bei Hypertriglyzeridämie.', 'Echium oil RCT: Reduced total cholesterol, LDL, oxLDL. Triglycerides -9% to -21%.', 'Bei erhöhten Lipidwerten als Ergänzung', 'Kuhnt 2014; Surette 2004'),
  ('fischoelalt-vegan', 'Fischöl-Alternative (vegan)', 'Fish Oil Alternative (Vegan)', 'Fischöl, vegan, Fischgeruch, Fischgeschmack, Allergie', 'fish oil, vegan, fish smell, fish allergy', 'Ernährung', 'Omega-3-Alternativen', 'ahiflower-oel, echiumoel, algenoel-dha', '⭐ KOMBINATION: SDA-Öl (Ahiflower/Echium) für EPA + Algenöl für DHA!', '-', '-', '⭐ VOLLSTÄNDIGE VEGANE FISCHÖL-ALTERNATIVE: SDA-Öle (Ahiflower, Echium) erhöhen EPA. Algenöl liefert DHA direkt. Kombination = alle Omega-3 ohne Fisch! ⚠️ SDA-Öle ALLEIN ersetzen Fischöl NICHT vollständig (kein DHA)!', 'Complete vegan fish oil alternative: SDA oil for EPA + algae oil for DHA.', 'Veganer, Vegetarier, Fischallergie', '⚠️ Immer mit Algen-DHA kombinieren!'),
  ('omega3-pflanzlich', 'Omega-3-Versorgung (pflanzlich/ALA)', 'Plant-based Omega-3 (ALA)', 'omega-3, ala, alpha-linolensäure, pflanzliche omega-3, veganes omega-3', 'omega-3, ala, alpha-linolenic acid, plant omega-3, vegan omega-3', 'Herzgesundheit', 'Omega-3-Versorgung', 'camelinaoel, leinoel, chiaoel, perilloel, hanfsamenoel, rapsoel', '✅✅ Camelinaöl (31-41% ALA) oder Leinöl (50-55% ALA) für maximale ALA-Aufnahme. Rapsöl (~9% ALA) für Alltagsküche.', '-', '-', '✅ EFSA Health Claim: 2g ALA/Tag für Cholesterin-Senkung. Camelinaöl: 5-6g für Claim; Rapsöl: ~22g für Claim.', 'ALA contributes to maintenance of normal blood cholesterol levels (2g/day)', 'Nein', '-'),
  ('cholesterin', 'Cholesterinmanagement / Dyslipidämie', 'Cholesterol Management / Dyslipidemia', 'cholesterin, ldl, hdl, triglyceride, dyslipidämie, lipidprofil', 'cholesterol, ldl, hdl, triglycerides, dyslipidemia, lipid profile', 'Herzgesundheit', 'Lipidstoffwechsel', 'rapsoel, camelinaoel, fischoel', '✅✅ Rapsöl: Meta-Analyse 42 RCTs - TC -0,27mmol/l, LDL -0,23mmol/l (PMID 33127255). ✅ Camelinaöl: Meta-Analyse - TC-Reduktion (PMID 36476379).', '-', '-', '✅✅ Rapsöl BESSER als Olivenöl bei LDL-Senkung (Meta-Analyse 2022, PMID 35866510). 19-30g/Tag empfohlen.', 'Canola oil superior to olive oil for LDL reduction', 'Bei stark erhöhten Werten', 'Ärztliche Kontrolle bei Dyslipidämie'),
  ('nafld', 'NAFLD / Fettlebererkrankung', 'NAFLD / Fatty Liver Disease', 'nafld, fettleber, lebererkrankung, leberverfettung', 'nafld, fatty liver, liver disease, hepatic steatosis', 'Lebergesundheit', 'Stoffwechsel', 'camelinaoel', '✅ Camelinaöl bei NAFLD: RCT 2021 (PMID 34423525) - 20g/Tag × 12 Wochen → hs-CRP -13%, LPS -33%, HOMA-IR -20%', '-', '-', '✅ Vielversprechende Ergebnisse bei NAFLD, aber nur 1 RCT. Weitere Studien nötig.', 'Camelina oil reduced inflammation markers in NAFLD (PMID 34423525)', 'Bei Lebererkrankung', 'Hepatologische Betreuung'),
  ('alltagskueche', 'Alltagsküche / Speiseöl', 'Everyday Cooking / Cooking Oil', 'kochen, braten, backen, speiseöl, küchenöl, alltagsküche', 'cooking, frying, baking, cooking oil, everyday kitchen', 'Ernährung', 'Speiseöle', 'rapsoel', '✅✅ RAPSÖL = BESTES ALLROUND-SPEISEÖL! Hoher Rauchpunkt (~230°C), neutraler Geschmack (raffiniert), beste Evidenz, günstig, EU GMO-frei.', '-', '-', '✅ Raffiniertes Rapsöl für Braten/Backen; Kaltgepresstes für Salate/Dressings. Camelinaöl (~245°C) auch zum Kochen geeignet.', 'Rapeseed/canola oil optimal for all cooking applications', 'Nein', '-'),
  ('stabiles-ala-oel', 'Oxidationsstabiles ALA-Öl', 'Oxidation-stable ALA Oil', 'stabiles öl, haltbares öl, nicht kühlpflichtig, lagerbeständig, oxidationsstabil', 'stable oil, shelf-stable, no refrigeration, oxidation stable', 'Omega-3-Versorgung', 'Praktische Anwendung', 'camelinaoel', '✅✅ CAMELINAÖL = BESTE WAHL für stabiles ALA-Öl! Rancimat 4,2-6,8h vs. Leinöl 3,7-4,7h. Haltbarkeit 18-24 Monate vs. 3-6 Monate bei Leinöl.', '-', '-', '✅✅ Camelinaöl EMPFEHLEN wenn Kühlaufbewahrung nicht möglich oder lange Haltbarkeit gewünscht!', 'Camelina oil combines high ALA with superior oxidation stability', 'Nein', '-'),
  ('pathogen-bindung', 'Pathogen-Bindung / Infektionsprävention', 'Pathogen Binding / Infection Prevention', 'Pathogen, Infektion, E. coli, Salmonella, Durchfall, Darm-Infektion', 'pathogen, infection, E. coli, Salmonella, diarrhea, gut infection', 'Immunologie', 'Infektabwehr', 'mannanoligosaccharide (⚠️ aber limitierte Humaneviden!)', '⚠️ MOS nur mit Einschränkung (fast nur Tierstudien!)', '-', '-', '⭐ EINZIGARTIGER MECHANISMUS! MOS bindet Pathogene mit Typ-1-Fimbrien (E. coli, Salmonella, Klebsiella). Bakterien binden an MOS statt an Darmepithel → Ausscheidung. ⚠️ ABER: >733 Studien fast alle bei Tieren! Nur wenige Humanstudien.', 'MOS binds pathogens with Type-1 fimbriae. Unique mechanism but ALMOST NO human studies!', 'Bei schweren Infektionen', 'Arzt konsultieren'),
  ('immunmodulation-mos', 'Immunmodulation', 'Immune Modulation', 'Immunsystem, Abwehrkräfte, Makrophagen, Immunstärkung', 'immune system, defense, macrophages, immune boost', 'Immunologie', 'Immunsystem', 'mannanoligosaccharide, beta-glucan (⚠️ MOS limitierte Humaneviden!)', '⚠️ MOS + Beta-Glucan (synergistisch, aber wenig Humanstudien zu MOS)', '-', '-', '⭐ MECHANISMUS: MOS aktiviert Makrophagen über Mannose-Rezeptor (CD206). Triggert Phagozytose, Zytokin-Produktion (IL-1β, TNF-α, IL-6). ⚠️ HUMANEVIDEN BEGRENZT! Beta-Glucan besser untersucht.', 'MOS activates macrophages via mannose receptor. Good mechanism but limited human studies.', 'Nein', '-'),
  ('darmgesundheit-mos', 'Darmgesundheit / Mikrobiom', 'Gut Health / Microbiome', 'Darmgesundheit, Mikrobiom, Darmflora, präbiotisch', 'gut health, microbiome, gut flora, prebiotic', 'Verdauung', 'Mikrobiom', '⚠️ BESSER: xylooligosaccharide, galactooligosaccharide, inulin', '❌ MOS NICHT für klassische präbiotische Wirkung! Besser: XOS, GOS, FOS.', '-', '-', '⚠️ MOS ist KEIN klassisches Präbiotikum! Geringe Fermentierbarkeit, wirkt primär durch Pathogen-Bindung. Für echte präbiotische Wirkung (SCFA, Bifidobakterien): XOS, GOS, FOS, Inulin verwenden!', 'MOS is NOT a classic prebiotic. Low fermentability. Use XOS/GOS/FOS for prebiotic effects.', 'Nein', '-'),
  ('durchfall-mos', 'Durchfallprävention', 'Diarrhea Prevention', 'Durchfall, Diarrhoe, Reisedurchfall, Antibiotika-assoziierter Durchfall', 'diarrhea, traveler''s diarrhea, antibiotic-associated diarrhea', 'Verdauung', 'Stuhlgang', 'mannanoligosaccharide + saccharomyces-boulardii', 'MOS + S. boulardii Kombination (⚠️ aber S. boulardii ist der Hauptwirkstoff!)', '-', '-', '⚠️ S. boulardii + MOS ist etabliert für Durchfallprävention - aber der Hauptwirkstoff ist S. BOULARDII, nicht MOS! MOS trägt zur Pathogen-Bindung bei. Florastor® enthält diese Kombination.', 'S. boulardii + MOS combo works, but S. boulardii is the main active!', 'Bei schwerem Durchfall', 'Arzt konsultieren, Dehydrierung vermeiden'),
  ('uti-harnwegsinfekt', 'Harnwegsinfekt-Prävention', 'UTI Prevention', 'Harnwegsinfekt, UTI, Blasenentzündung, E. coli', 'urinary tract infection, UTI, bladder infection, E. coli', 'Urologie', 'Harnwege', '⚠️ BESSER: d-mannose', '⚠️ MOS nur Pilotstudie (n=9)! D-Mannose besser untersucht für UTI.', '-', '-', '⚠️ SEHR LIMITIERTE EVIDENZ! Eine Pilotstudie (2014, n=9 Frauen) testete MOS bei rezidivierenden UTI - unkontrolliert, keine Bestätigung. D-MANNOSE ist für UTI besser untersucht (auch Mannose-Bindung an E. coli FimH).', 'Only ONE tiny pilot study (n=9). D-Mannose is better studied for UTI.', 'Bei rezidivierenden UTI', 'Urologische Abklärung'),
  ('gewichtsreduktion-mos', 'Gewichtsreduktion', 'Weight Loss', 'Abnehmen, Gewichtsverlust, Fettabbau', 'weight loss, fat loss', 'Stoffwechsel', 'Energiebilanz', 'mannanoligosaccharide (⚠️ nur bei Männern, begrenzte Evidenz)', '⚠️ MOS nur bei MÄNNERN wirksam (Studie), bei Frauen KEIN Effekt!', '-', '-', '⚠️ BEGRENZTE EVIDENZ! Kaffee-MOS Studie (2010-2013): 4 g/Tag über 12 Wochen. Bei MÄNNERN: -6,0% Gewicht (vs. -2,3% Placebo). Bei FRAUEN: KEIN signifikanter Effekt! Geschlechtsabhängig.', 'Coffee-MOS study: Works in MEN (-6% weight), NOT in women. Limited evidence.', 'Nein', '-'),
  ('diabetische-neuropathie-gla', 'Diabetische Neuropathie (GLA)', 'Diabetic Neuropathy (GLA)', 'Neuropathie, Diabetes, Nervenschmerzen, Polyneuropathie', 'diabetic neuropathy, nerve damage, polyneuropathy', 'Nervensystem', 'Diabetische Komplikationen', 'gamma-linolensaeure', 'GLA 480 mg/Tag (Studien)', '-', '-', '⭐ MODERATE EVIDENZ! γ-Linolenic Acid Multicenter Trial 1993: 480 mg GLA/Tag, 1 Jahr, n=111. 13 von 16 Parametern signifikant verbessert (Nervenleitgeschwindigkeit, SNAP, CMAP, Schwellen). Besser bei gut eingestelltem Diabetes.', 'Moderate evidence: GLA 480mg/day improves nerve conduction in diabetic neuropathy.', 'Ja - besonders bei gut eingestelltem Diabetes', 'Diabetes Care 1993'),
  ('sjogren-trockene-augen', 'Trockene Augen / Sjögren-Syndrom (GLA)', 'Dry Eyes / Sjögren Syndrome (GLA)', 'trockene Augen, Sjögren, Keratoconjunctivitis sicca', 'dry eyes, Sjögren syndrome, keratoconjunctivitis sicca', 'Augen', 'Augenbeschwerden', 'gamma-linolensaeure', 'GLA 15-300 mg/Tag', '-', '-', 'MODERATE EVIDENZ: Mehrere RCTs (Aragona 2005, Barabino) zeigten Verbesserung der Tränen-PGE1-Spiegel und Symptome. Mechanistisch plausibel: PGE1 stimuliert Tränenproduktion.', 'Moderate evidence for dry eyes/Sjögren. PGE1 stimulates tear production.', 'Als Zusatz zur Standardtherapie', 'Aragona 2005'),
  ('atopische-dermatitis-gla', '⚠️ Atopische Dermatitis / Neurodermitis (GLA)', 'Atopic Dermatitis (GLA)', 'Neurodermitis, Ekzem, atopisches Ekzem, trockene Haut', 'atopic dermatitis, eczema, atopic eczema', 'Haut', 'Entzündliche Hauterkrankungen', '-', '⚠️ GLA NICHT EMPFOHLEN für Atopische Dermatitis!', 'gamma-linolensaeure, nachtkerzenoel, borretschoel', '-', '⚠️ COCHRANE 2013: NICHT WIRKSAM! 27 RCTs, n=1596. Meta-Analyse: MD -2,22 (CI -10,48 bis 6,04) - NICHT SIGNIFIKANT. UK MCA hat 2002 Zulassung für EPO bei Ekzem ZURÜCKGEZOGEN. "Further studies would be hard to justify."', 'WARNING: Cochrane 2013 shows NO efficacy for atopic dermatitis. Do not recommend.', 'Nein - bei anhaltenden Beschwerden', '⚠️ GLA NICHT EMPFEHLEN für Neurodermitis!'),
  ('pms-mastalgie-gla', '⚠️ PMS / Zyklische Mastalgie (GLA)', 'PMS / Cyclic Mastalgia (GLA)', 'PMS, Brustspannen, Mastalgie, prämenstruell', 'PMS, breast pain, mastalgia, premenstrual', 'Hormone', 'Menstruationsbeschwerden', '-', '⚠️ GLA NICHT EMPFOHLEN - schwache Evidenz', 'gamma-linolensaeure', '-', '⚠️ SCHWACHE EVIDENZ! Meta-Analyse Budeiri 1996: Nur 7 Studien, die 2 besten zeigten KEINE Wirkung. Systematische Review 2021: EPO KEIN Unterschied vs. Placebo bei Mastalgie.', 'WARNING: Meta-analyses show no benefit for PMS/mastalgia vs placebo.', 'Bei anhaltenden Beschwerden Arzt aufsuchen', '⚠️ NICHT für PMS/Mastalgie empfehlen!'),
  ('pathogen-reduktion', 'Pathogen-Reduktion / Darminfektionen', 'Pathogen Reduction / Gut Infections', 'e.coli, salmonella, durchfall, darminfekt, magen-darm', 'e.coli, salmonella, diarrhea, gut infection, gastroenteritis', 'Darmgesundheit', 'Infektabwehr', 'mannanoligosaccharide', '⚠️⚠️ MOS bindet Pathogene (E. coli, Salmonella) über Typ-1-Fimbrien - ABER NUR TIERSTUDIEN! KEINE Humanstudien zu Durchfallprävention!', '-', '-', '⚠️⚠️ NICHT für Durchfallprävention beim Menschen empfehlen - Evidenz fehlt!', 'MOS: No human studies on pathogen reduction', 'Bei akutem Durchfall', 'Ärztliche Behandlung bei schweren GI-Infekten'),
  ('koerpergewicht-mos', 'Körpergewicht / Körperzusammensetzung', 'Body Weight / Body Composition', 'gewicht, abnehmen, körperfett, bauchumfang', 'weight, weight loss, body fat, waist circumference', 'Stoffwechsel', 'Gewichtsmanagement', 'mannanoligosaccharide', '⚠️ BEGRENZTE EVIDENZ! 1 RCT (n=54): 4g/Tag Kaffee-MOS × 12 Wochen → reduziertes Körpervolumen NUR BEI MÄNNERN (PMID: 20861211)', '-', '-', '⚠️ NICHT für Gewichtsmanagement empfehlen - nur 1 Studie, Effekt nur bei Männern', 'Only 1 RCT, effect only in males', 'Nein', '-'),
  ('obstipation-ballaststoff', 'Obstipation / Verstopfung', 'Constipation', 'Verstopfung, Obstipation, harter Stuhl, seltener Stuhlgang', 'constipation, hard stool, infrequent bowel movements', 'Verdauung', 'Stuhlgang', 'zellulose, hemicellulose, methylcellulose', '1. Methylcellulose (Zellulose-Derivat), 2. Psyllium, 3. Glucomannan', '-', '-', '⭐ ZELLULOSE/METHYLCELLULOSE: Mechanische Wirkung durch Stuhlvolumenerhöhung. Wirkt durch Wasserbindung, NICHT Fermentation. Gut verträglich (wenig Blähungen). Mit viel Wasser einnehmen!', 'Cellulose works mechanically by increasing stool bulk. Take with plenty of water.', 'Bei chronischer Obstipation >2 Wochen', 'Organische Ursachen ausschließen'),
  ('cholesterin-ballaststoff', 'Cholesterinsenkung', 'Cholesterol Reduction', 'Cholesterin, LDL, Hypercholesterinämie, Blutfette', 'cholesterol, LDL, hypercholesterolemia, blood lipids', 'Stoffwechsel', 'Lipidstoffwechsel', '⭐ hemicellulose (Beta-Glucan!)', '⭐ 1. Beta-Glucan (Hafer/Gerste) ≥3g/Tag - EFSA CLAIM!', 'zellulose (unwirksam!)', '-', '⭐ BETA-GLUCAN ist der EINZIGE Ballaststoff mit EFSA-Claim für Cholesterin! ≥3g/Tag senkt LDL um 0,19-0,25 mmol/L. Mechanismus: Viskoses Gel bindet Gallensäuren. ❌ Zellulose ist UNWIRKSAM (keine Viskosität)!', 'Beta-glucan is the ONLY fiber with EFSA cholesterol claim. Cellulose is INEFFECTIVE.', 'Bei Hypercholesterinämie', 'Ärztliche Kontrolle, Statine prüfen'),
  ('blutzucker-ballaststoff', 'Blutzuckerregulation', 'Blood Sugar Regulation', 'Blutzucker, postprandiale Glykämie, Diabetes, Glukose', 'blood sugar, postprandial glycemia, diabetes, glucose', 'Stoffwechsel', 'Glukosemetabolismus', '⭐ hemicellulose (Beta-Glucan, Arabinoxylan, HPMC)', '⭐ 1. Beta-Glucan (4g/30g KH), 2. Arabinoxylan (8g/100g KH), 3. HPMC (4g/Mahlzeit)', 'zellulose (unwirksam!)', '-', '⭐ DREI EFSA CLAIMS: Beta-Glucan, Arabinoxylan, HPMC senken postprandialen Blutzuckeranstieg. Mechanismus: Viskosität verzögert Magenentleerung und Glukoseabsorption. ❌ Zellulose ist UNWIRKSAM!', 'Three EFSA claims for blood sugar: Beta-glucan, Arabinoxylan, HPMC. Cellulose INEFFECTIVE.', 'Bei Diabetes', 'Diabetologische Beratung'),
  ('darmgesundheit-ballaststoff', 'Darmgesundheit / Mikrobiom', 'Gut Health / Microbiome', 'Darmgesundheit, Mikrobiom, Darmflora, präbiotisch', 'gut health, microbiome, gut flora, prebiotic', 'Verdauung', 'Mikrobiom', '⭐ hemicellulose (fermentierbar)', '⭐ 1. Beta-Glucan, 2. Glucomannan, 3. PHGG. ❌ NICHT Zellulose!', 'zellulose (nicht präbiotisch!)', '-', '⭐ Fermentierbare HEMICELLULOSEN sind präbiotisch! Beta-Glucan fördert Bifidobakterien, produziert Butyrat. ❌ ZELLULOSE ist NICHT präbiotisch (~8% Fermentation). Für Präbiotik besser: XOS, GOS, FOS, Inulin.', 'Fermentable hemicelluloses are prebiotic. Cellulose is NOT prebiotic.', 'Nein', '-'),
  ('praebiotik-scfa', 'Präbiotische SCFA-Produktion', 'Prebiotic SCFA Production', 'kurzkettige Fettsäuren, SCFA, Butyrat, Propionat, Acetat, Buttersäure', 'short-chain fatty acids, SCFA, butyrate, propionate, acetate', 'Darmgesundheit', 'Präbiotik', 'arabinoxylanoligosaccharide, xos, gos, fos, inulin', '1. AXOS (starke Propionat-Stimulation); 2. FOS/Inulin; 3. XOS; 4. GOS', '-', '-', '✅ AXOS: Starke Propionat- und Butyrat-Produktion durch Cross-feeding (PMID 26319874). ⚠️ Glutenspuren!', '✅ AXOS: Strong propionate and butyrate production via cross-feeding. ⚠️ Gluten traces!', 'Nein', '-'),
  ('blutzucker-postprandial', 'Postprandiale Blutzuckerkontrolle', 'Postprandial Blood Glucose Control', 'Blutzucker, Glukose, postprandial, nach dem Essen, Insulinsensitivität', 'blood sugar, glucose, postprandial, after meal, insulin sensitivity', 'Stoffwechsel', 'Blutzucker', 'arabinoxylan, arabinoxylanoligosaccharide', '1. Arabinoxylan (EFSA Health Claim!); 2. AXOS (nur akute Effekte)', '-', '-', '⚠️ EFSA Health Claim nur für ARABINOXYLAN (Polysaccharid ≥8g), NICHT für AXOS (Oligosaccharid)! AXOS: Nur akute Effekte, keine Langzeitdaten (PMID 26169871). ⚠️ Glutenspuren!', '⚠️ EFSA Health Claim only for ARABINOXYLAN (polysaccharide ≥8g), NOT for AXOS (oligosaccharide)!', 'Bei Diabetes: Ja', 'Blutzucker engmaschig kontrollieren bei Kombination mit Antidiabetika'),
  ('obstipation-stuhl', 'Stuhlregulation & Obstipation', 'Stool Regulation & Constipation', 'Verstopfung, Obstipation, Stuhlgang, Stuhlfrequenz, Stuhlkonsistenz', 'constipation, bowel movement, stool frequency, stool consistency', 'Darmgesundheit', 'Stuhlregulation', 'arabinoxylanoligosaccharide, ballaststoffe, inulin, flohsamen', '1. Ballaststoffe; 2. Flohsamen; 3. AXOS (weichere Stuhlkonsistenz bei 15g/Tag)', '-', '-', '⚠️ AXOS: Limitierte Evidenz für Stuhlregulation (PMID 31983281). Weichere Konsistenz bei 15g/Tag. ⚠️ Glutenspuren!', '⚠️ AXOS: Limited evidence for stool regulation. Softer consistency at 15g/day. ⚠️ Gluten traces!', 'Bei chronischer Obstipation: Ja', 'Chronische Obstipation ärztlich abklären'),
  ('omega-6-versorgung-niger', 'Omega-6-Versorgung (Nigersamenöl)', 'Omega-6 Supply (Niger Seed Oil)', 'Omega-6, Linolsäure, essentielle Fettsäuren', 'omega-6, linoleic acid, essential fatty acids', 'Fettsäuren', 'Essentielle Fettsäuren', 'nigersamenoel', 'Nigersamenöl als Speiseöl (nicht als Supplement)', '-', '-', '⚠️ KEINE HUMANSTUDIEN zu Nigersamenöl als Supplement! Nur als traditionelles Speiseöl in Äthiopien/Indien verwendet. Evidenz: NUR TIERSTUDIEN (Lipidprofil bei Ratten).', 'No human clinical evidence for Niger Seed Oil supplements. Traditional cooking oil only.', 'Bei spezifischen Beschwerden andere Fettsäure-Quellen wählen', '⚠️ NICHT EMPFEHLEN - keine Evidenz'),
  ('aad-praevention-lacto', 'Antibiotika-assoziierte Diarrhoe (Prävention)', 'Antibiotic-Associated Diarrhea Prevention', 'Durchfall nach Antibiotika, AAD, Antibiotika-Nebenwirkung', 'antibiotic diarrhea, AAD, antibiotic side effect', 'Verdauung', 'Diarrhoe-Prävention', 'lactobacillus-acidophilus, lactobacillus-rhamnosus-gg, saccharomyces-boulardii', '⭐ L. rhamnosus GG (ESPGHAN 1. Wahl), S. boulardii (1. Wahl), L. acidophilus in Kombination', '-', '-', '✅ MODERATE EVIDENZ (in Kombination)! Cochrane 2019: 33 RCTs, n=6352 Kinder, NNTB=9. Bei Hochdosis (≥5×10⁹ CFU/Tag): NNTB=6. ⚠️ L. acidophilus ALLEIN: Schwächere Evidenz als LGG oder S. boulardii!', 'Moderate evidence for AAD prevention in combination. L. rhamnosus GG or S. boulardii preferred as single strains.', 'Bei anhaltender Diarrhoe > 3 Tage', 'L. acidophilus in Kombination mit anderen Stämmen. Mind. 5×10⁹ CFU/Tag.'),
  ('cdad-praevention-lacto', 'C. difficile-assoziierte Diarrhoe (Prävention)', 'C. difficile-Associated Diarrhea Prevention', 'C. difficile, Clostridioides, CDAD, CDI, Krankenhausdiarrhoe', 'C. difficile, CDI, CDAD, hospital diarrhea', 'Verdauung', 'Infektions-Prävention', 'lactobacillus-acidophilus, lactobacillus-casei', '⭐ L. acidophilus + L. casei KOMBINATION!', '-', '-', '⭐ STARKE EVIDENZ für KOMBINATION! Meta-Analyse: L. acidophilus + L. casei → RR 0,05 (95% CI 0,01-0,36). ⚠️ ABER: ESCMID/IDSA-Leitlinien empfehlen KEINE routinemäßige Probiotika-Anwendung zur primären CDI-Prävention.', 'Strong evidence for L. acidophilus + L. casei combination. However, guidelines do not recommend routine use.', 'Bei CDI-Symptomen sofort Arzt', '⭐ L. acidophilus + L. casei Kombination. Leitlinien: Keine Routine-Empfehlung.'),
  ('bv-prophylaxe-lacto', 'Bakterielle Vaginose (Rezidiv-Prophylaxe)', 'Bacterial Vaginosis Recurrence Prevention', 'Bakterielle Vaginose, BV, Scheidenflora, vaginale Dysbiose', 'bacterial vaginosis, BV, vaginal dysbiosis', 'Frauengesundheit', 'Vaginale Gesundheit', 'lactobacillus-acidophilus', 'L. acidophilus La-14 + L. rhamnosus in Kombination, nach Antibiotika-Therapie', '-', '-', '✅ MODERATE EVIDENZ als Adjuvanz! Meta-Analyse Chen 2022: OR 0,19 (95% CI 0,08-0,44). Reznichenko 2020: BV-Rezidiv 18,3% vs. 32,1% Placebo. DGGG-Leitlinie 2023: Komplementär nach Antibiotika (starker Konsens). ⚠️ ACOG 2020: NICHT empfohlen.', 'Moderate evidence as adjunct after antibiotic therapy. DGGG recommends, ACOG does not.', 'Bei Symptomen Arzt aufsuchen', 'Nach Antibiotika-Therapie adjuvant. Oral: Kolonisation vaginal nach 1-2 Wochen.'),
  ('laktoseintoleranz-lacto', 'Laktoseintoleranz (Symptomlinderung)', 'Lactose Intolerance', 'Laktoseintoleranz, Milchzucker, Laktase-Mangel', 'lactose intolerance, lactase deficiency', 'Verdauung', 'Enzymunterstützung', 'lactobacillus-acidophilus', 'L. acidophilus NCFM® (spezifisch untersucht)', '-', '-', '✅ MODERATE EVIDENZ! L. acidophilus produziert β-Galaktosidase und kann Laktoseverdauung verbessern. NCFM-Stamm spezifisch untersucht. ⚠️ EFSA Health Claim gilt nur für L. bulgaricus + S. thermophilus in Joghurt, NICHT für L. acidophilus!', 'Moderate evidence. NCFM strain specifically studied for lactose digestion improvement.', 'Bei starken Symptomen Arzt', 'L. acidophilus NCFM® oder Acidophilus-Milch. Alternativ: Laktase-Enzyme.'),
  ('gastroenteritis-kinder-lacto', 'Akute Gastroenteritis (Kinder)', 'Acute Gastroenteritis (Children)', 'Magen-Darm-Infekt, Rotavirus, Norovirus, Brechdurchfall', 'gastroenteritis, stomach flu, rotavirus, norovirus', 'Verdauung', 'Infektions-Therapie', 'lactobacillus-acidophilus', 'L. acidophilus in KOMBINATION (nicht allein)', '-', '-', '⚠️ SCHWACHE EVIDENZ ALS MONOPRÄPARAT! Cheng 2022 Meta-Analyse: L. acidophilus allein NICHT signifikant (6 RCTs, MD -0,47). L. acidophilus + andere: Signifikant (9 RCTs, MD -0,91). Durchfalldauer-Reduktion: ~0,69 Tage. ⚠️ Dosen <10⁹ CFU/Tag: KEIN EFFEKT!', 'Weak evidence as monotherapy. Only effective in combination. Doses <10⁹ CFU ineffective.', 'Bei Dehydration sofort Arzt!', '⚠️ NICHT als Monopräparat! Nur in Kombination. Mind. 10⁹ CFU/Tag.'),
  ('darmbarriere-leaky-gut', 'Darmbarriere / Leaky Gut', 'Gut Barrier / Leaky Gut', 'Leaky Gut, Darmbarriere, Tight Junctions, Zonulin, intestinale Permeabilität', 'leaky gut, gut barrier, tight junctions, zonulin, intestinal permeability', 'Verdauung', 'Darmbarriere', '⭐ butyrat', '⭐ 1. Butyrat (reguliert Tight-Junction-Proteine hoch)', '-', '-', '⭐ MECHANISMUS GUT BELEGT: Butyrat reguliert Claudin-1, Claudin-7, Occludin, ZO-1 hoch (Tight Junctions). Geriatrische Studie (n=130): 300 mg/Tag, 16 Wo → reduziertes Plasma-Zonulin und LBP. IBS-Studie 2025: Verbesserte transzelluläre Hyperpermeabilität.', 'Butyrate upregulates tight junction proteins. Reduces zonulin.', 'Nein', '-'),
  ('darm-hirn-achse', 'Darm-Hirn-Achse / Psyche', 'Gut-Brain Axis / Mental Health', 'Depression, Angst, Stimmung, Darm-Hirn-Achse, Psychobiom', 'depression, anxiety, mood, gut-brain axis, psychobiome', 'Neurologie', 'Darm-Hirn-Achse', 'butyrat (begrenzte Evidenz)', 'Butyrat (⚠️ gemischte Ergebnisse)', '-', '-', '⚠️ BEGRENZTE EVIDENZ! MDD-Patienten: Reduzierte Butyrat-Produzenten. ButyraGen® RCT: Kein Gesamtbenefit, ABER: Verbesserung bei Teilnehmern OHNE GI-Erkrankung. Angst: MÄNNER zeigten 2x höhere Wahrscheinlichkeit klinisch bedeutsamer Verbesserung.', 'Limited evidence. Improvements in anxiety (men), depression (if no GI disease).', 'Ja (bei Depression/Angst)', 'Psychiatrische Betreuung'),
  ('autismus-asd', 'Autismus-Spektrum-Störung (ASD)', 'Autism Spectrum Disorder', 'Autismus, ASD, GI-Beschwerden bei Autismus', 'autism, ASD, GI symptoms in autism', 'Neurologie', 'Entwicklungsstörungen', 'butyrat (LAUFENDE STUDIEN)', '⚠️ Butyrat (NCT06514573 läuft)', '-', '-', '⚠️ LAUFENDE FORSCHUNG! Studie NCT06514573: 128 ASD-Kinder, 20 mg/kg/Tag, 16 Wochen. Tierstudien: Natriumbutyrat verbesserte Sozialverhalten. Humanstudien: NOCH NICHT ABGESCHLOSSEN.', 'Ongoing research. No completed human trials for ASD.', 'Ja (ASD ist Arzt-Pflicht)', 'Interdisziplinäre Betreuung'),
  ('lignin-keine-indikation', '❌ Lignin: Keine Supplement-Indikation', 'Lignin: No Supplement Indication', 'Lignin', 'lignin', '-', '-', '❌ NICHT EMPFOHLEN', '❌ Lignin ist KEIN relevantes Supplement', '-', '-', '❌ LIGNIN: KEINE belegte Indikation als Supplement! Einzige Studie (n=10, 1983) ohne Wirkungsnachweis. Natürliche Aufnahme über Ernährung ist ausreichend.', 'Lignin is NOT a relevant supplement. No evidence.', '-', '-'),
  ('obstipation-stuhlfrequenz', 'Obstipation / Stuhlfrequenz', 'Constipation / Stool Frequency', 'Verstopfung, Obstipation, Stuhlgang, Stuhlfrequenz, Darmträgheit, Defäkation', 'constipation, bowel movement, stool frequency, defecation', 'Darmgesundheit', 'Stuhlregulation', 'inulin, flohsamenschalen, ballaststoffe', '1. ✅✅ INULIN (EFSA-Claim bei 12g/Tag!); 2. Flohsamenschalen; 3. Ballaststoffe allgemein', 'IBS, SIBO, Fructan-Intoleranz', 'oligofructose (schlechtere Verträglichkeit)', '✅✅ EINZIGER EFSA-CLAIM FÜR PRÄBIOTIKA! Natives Chicorée-Inulin 12g/Tag erhöht Stuhlfrequenz um +1/Woche. ⚠️⚠️ HIGH-FODMAP - bei IBS kontraindiziert!', '✅✅ ONLY prebiotic with EFSA claim! Native chicory inulin 12g/day increases stool frequency. ⚠️⚠️ HIGH-FODMAP - contraindicated in IBS!', 'Bei chronischer Obstipation: Ja', 'Blut im Stuhl, starke Bauchschmerzen, ungewollter Gewichtsverlust'),
  ('calcium-knochen', 'Calciumabsorption & Knochengesundheit', 'Calcium Absorption & Bone Health', 'Calciumaufnahme, Knochen, Osteoporose, Knochendichte, Mineralstoffe', 'calcium absorption, bone health, osteoporosis, bone density', 'Knochengesundheit', 'Mineralstoffaufnahme', 'inulin, calcium, vitamin-d3', '1. Inulin/Synergy1 (für Calciumabsorption); 2. Calcium; 3. Vitamin D3', '-', '-', '✅ Inulin/Synergy1 erhöht Calciumabsorption um +8,5% bei Jugendlichen (PMID 16091751). Nach 1 Jahr: +35g Knochenmineralgehalt. ⚠️ EFSA-Claim für Ca-Absorption wurde ABGELEHNT (Substanzcharakterisierung).', '✅ Inulin/Synergy1 increases calcium absorption by +8.5% in adolescents. ⚠️ EFSA claim for Ca absorption REJECTED.', 'Bei Osteoporose-Risiko: Ja', 'Vitamin D und Calcium-Status prüfen'),
  ('ibs-warnung', '⚠️⚠️ REIZDARMSYNDROM (IBS) - WARNUNG', '⚠️⚠️ IRRITABLE BOWEL SYNDROME - WARNING', 'Reizdarm, IBS, IBS-D, IBS-C, FODMAP, Bauchschmerzen, Blähungen', 'irritable bowel syndrome, IBS, FODMAP, abdominal pain, bloating', 'Darmgesundheit', 'IBS', 'gos, xos', '1. ✅ GOS (moderates FODMAP, gut verträglich bei IBS); 2. ✅ XOS (LOW-FODMAP); 3. ❌❌ NICHT: Inulin, Oligofructose', '-', 'inulin, oligofructose', '❌❌❌ INULIN UND OLIGOFRUCTOSE SIND HIGH-FODMAP! Bei IBS kontraindiziert! 75-86% der IBS-Patienten profitieren von FOS-MEIDUNG! Stattdessen GOS oder XOS empfehlen.', '❌❌❌ INULIN AND OLIGOFRUCTOSE ARE HIGH-FODMAP! Contraindicated in IBS! 75-86% of IBS patients benefit from avoiding FOS! Recommend GOS or XOS instead.', 'Bei IBS: JA', 'Low-FODMAP-Diät mit Ernährungsberater'),
  ('sibo', 'SIBO (Dünndarm-Fehlbesiedlung)', 'Small Intestinal Bacterial Overgrowth', 'SIBO, Dünndarm-Fehlbesiedlung, Bakterienüberwuchs, Malabsorption', 'SIBO, small intestinal bacterial overgrowth, malabsorption', 'Verdauung', 'Dünndarm', '⭐ natriumbutyrat (enterisch beschichtet)', '⭐ 1. Natriumbutyrat 1.500 mg/Tag (RCT bei T2DM)', '-', '-', '⭐ RCT (n=52, Panufnik 2024): 1.500 mg MSB/Tag über 12 Wochen. Signifikante SIBO-Reduktion (p=0,001), Schmerzreduktion (p=0,001), weniger Blähungen (p<0,001). Wirkmechanismus: antiinflammatorisch, antimikrobiell, Barrierestärkung.', 'RCT: 1,500 mg/day for 12 weeks significantly reduced SIBO prevalence.', 'Ja (SIBO ist Arzt-Pflicht)', 'Atemtest zur Diagnose'),
  ('divertikelkrankheit', 'Divertikelkrankheit (Prävention)', 'Diverticular Disease Prevention', 'Divertikel, Divertikulose, Divertikulitis, SUDD', 'diverticula, diverticulosis, diverticulitis', 'Verdauung', 'Kolon', '⭐ natriumbutyrat (enterisch beschichtet)', '⭐ 1. Natriumbutyrat 300-400 mg/Tag', '-', '-', '⭐ RCT (n=52, 12 MONATE!): 300 mg MSB/Tag. Signifikant weniger Divertikulitis-Episoden, verbesserte Lebensqualität. SUDD-Studie (n=59): 400 mg/Tag → erhöhte Alpha-Diversität, reduzierte Schmerzen.', '12-month RCT: 300 mg/day reduced diverticulitis episodes.', 'Bei Divertikulitis ja', 'Koloskopie zur Diagnose'),
  ('post-antibiotika-dysbiose', 'Post-Antibiotika-Dysbiose', 'Post-Antibiotic Dysbiosis', 'Dysbiose nach Antibiotika, Durchfall nach Antibiotika, Darmflora-Störung', 'post-antibiotic dysbiosis, antibiotic-associated diarrhea', 'Verdauung', 'Mikrobiom', '⭐ tributyrin', '⭐ 1. Tributyrin (während + 4-8 Wochen nach Antibiotika)', '-', '-', '⭐ Tierstudie: Tributyrin schützt Roseburia hominis während Antibiotika. Erhält Tight-Junction-Proteine (ZO-1, Occludin). Reduziert Endotoxin. Empfehlung: Während Antibiotika beginnen, 4-8 Wochen fortsetzen.', 'Tributyrin protects Roseburia hominis and tight junctions during antibiotics.', 'Nein', '-'),
  ('multiple-sklerose', 'Multiple Sklerose (adjuvant)', 'Multiple Sclerosis', 'MS, Multiple Sklerose, Neuroinflammation', 'MS, multiple sclerosis, neuroinflammation', 'Neurologie', 'Autoimmun', 'propionat (besser belegt), butyrat (präklinisch)', '⚠️ Propionat besser belegt als Butyrat bei MS!', '-', '-', '⚠️ MS-Patienten: Reduzierte Butyrat-Gene. Propionat-Studie (3 Jahre): Reduzierte jährliche Schubrate. SerBut (O-Butyryl-L-Serin) passiert BBB, verhindert EAE im Tiermodell. Für MS: Propionat derzeit bessere Evidenz!', 'Propionate better studied for MS. Butyrate preclinical only.', 'Ja (MS ist Arzt-Pflicht)', 'Neurologische Betreuung'),
  ('inulin-quellenauswahl', 'Inulin-Quellenauswahl (Chicorée vs. Topinambur)', 'Inulin Source Selection', 'Inulin, Chicorée, Topinambur, Jerusalem-Artischocke, Quelle, Herkunft', 'inulin, chicory, jerusalem artichoke, source, origin', 'Präbiotika', 'Produktauswahl', 'zichorienwurzel-inulin, topinambur-inulin', '1. ✅✅✅ CHICORÉE-INULIN (ERSTE WAHL! EFSA-Claim, beste Löslichkeit, höchste Standardisierung); 2. ⚠️ Topinambur nur als Alternative OHNE Health Claim', '-', '-', '✅✅✅ IMMER Chicorée-Inulin bevorzugen! Gründe: 1) EINZIGER EFSA Health Claim (12g/Tag für Darmfunktion), 2) 25x bessere Löslichkeit (118,7 vs. 4,6 g/L), 3) Höhere Standardisierung (88-100% vs. 55-90%). Topinambur ist funktionell äquivalent (PMID 17445348) aber OHNE Claim-Zulassung!', '✅✅✅ ALWAYS prefer chicory inulin! 1) ONLY EFSA claim, 2) 25x better solubility, 3) Higher standardization. Topinambur functionally equivalent but NO claim!', 'Nein', '-'),
  ('aad-praevention-lgg', 'Antibiotika-assoziierte Diarrhoe (Prävention) - LGG', 'Antibiotic-Associated Diarrhea Prevention - LGG', 'Durchfall nach Antibiotika, AAD, Antibiotika-Nebenwirkung', 'antibiotic diarrhea, AAD, antibiotic side effect', 'Verdauung', 'Diarrhoe-Prävention', 'lacticaseibacillus-rhamnosus, saccharomyces-boulardii', '⭐ L. rhamnosus GG (ESPGHAN 1. Wahl für Kinder), S. boulardii', '-', '-', '⭐ STARKE EVIDENZ bei Kindern! Meta-Analyse: RR 0,48 (95% CI 0,26-0,89), NNT=8. Bei H. pylori-Eradikation: RR 0,26. ⚠️ Bei Erwachsenen: NICHT signifikant (RR 0,48, CI 0,20-1,15).', 'Strong evidence in children (NNT=8). Not significant in adults.', 'Bei anhaltender Diarrhoe > 3 Tage', '⭐ LGG ≥5×10⁹ CFU/Tag. ESPGHAN STARK empfohlen.'),
  ('akute-gastroenteritis-lgg', 'Akute Gastroenteritis (Kinder)', 'Acute Gastroenteritis (Children)', 'Magen-Darm-Infekt, Durchfall, Erbrechen, Rotavirus', 'gastroenteritis, diarrhea, vomiting, rotavirus', 'Verdauung', 'Infektions-Therapie', 'lacticaseibacillus-rhamnosus', 'L. rhamnosus GG', '-', '-', '✅ MODERATE EVIDENZ! Meta-Analyse: Durchfalldauer -0,85 Tage (95% CI -1,15 bis -0,56). ⚠️ ABER: NEJM 2018 (n=943) zeigte KEINEN Nutzen! ESPGHAN: Schwache Empfehlung.', 'Moderate evidence. Meta-analyses positive, but large NEJM 2018 trial negative. ESPGHAN weak recommendation.', 'Bei Dehydration sofort Arzt!', 'LGG ≥10¹⁰ CFU/Tag für 5-7 Tage. Evidenz kontrovers.'),
  ('ekzem-praevention-hn001', 'Ekzem-Prävention (perinatal)', 'Eczema Prevention (Perinatal)', 'Neurodermitis, atopische Dermatitis, Ekzem, Allergie-Prävention', 'eczema, atopic dermatitis, allergy prevention', 'Haut', 'Allergie-Prävention', 'lacticaseibacillus-rhamnosus', '⭐ L. rhamnosus HN001 (NICHT LGG!)', '-', '-', '⭐ STARKE EVIDENZ für HN001! Wickens-Studien: 50% Reduktion Ekzem-Prävalenz bis 11 Jahre (HR 0,56). ⚠️ LGG NICHT signifikant! ⚠️ Mütterliche Supplementierung ALLEIN (ohne Säuglings-Supp.) KEIN Effekt!', 'Strong evidence for HN001 strain (Wickens studies). LGG NOT effective for eczema.', 'Bei schwerem Ekzem Dermatologe', '⭐ HN001 6×10⁹ CFU/Tag ab 35. SSW (Mutter) + Säugling bis 2 Jahre.'),
  ('vaginale-gesundheit-gr1', 'Bakterielle Vaginose (Behandlung + Prophylaxe)', 'Bacterial Vaginosis Treatment', 'Bakterielle Vaginose, BV, Scheidenflora, Intimgesundheit', 'bacterial vaginosis, BV, vaginal health', 'Frauengesundheit', 'Vaginale Gesundheit', 'lacticaseibacillus-rhamnosus', '⭐ L. rhamnosus GR-1 + L. reuteri RC-14', '-', '-', '⭐ MODERATE EVIDENZ! Martinez 2009: Tinidazol + GR-1/RC-14 vs. Placebo: Heilungsrate 87,5% vs. 50% (p=0,001). Orale Einnahme führt zu vaginaler Kolonisation nach 1-2 Wochen.', 'Moderate evidence. GR-1 + RC-14 combination (UREX) significantly improves BV cure rates.', 'Bei Symptomen Arzt aufsuchen', '⭐ GR-1 + RC-14 (UREX): 2×5×10⁹ CFU/Tag oral. Nach Antibiotika-Therapie.'),
  ('atemwegsinfekte-lgg', 'Atemwegsinfekte (Prävention)', 'Respiratory Tract Infection Prevention', 'Erkältung, grippaler Infekt, Otitis media, Atemwegsinfekt', 'common cold, RTI, respiratory infection, otitis media', 'Immunsystem', 'Infektions-Prävention', 'lacticaseibacillus-rhamnosus', 'L. rhamnosus GG', '-', '-', '✅ MODERATE EVIDENZ! Meta-Analyse (4 RCTs, n=1805): Akute Otitis media RR 0,76; URTIs RR 0,62 (NNT=4!); Antibiotikaverbrauch RR 0,80.', 'Moderate evidence. NNT=4 for URTI prevention in children.', 'Bei schwerem Verlauf Arzt', 'LGG 10⁹-10¹⁰ CFU/Tag über Erkältungssaison.'),
  ('cdi-praevention-casei', 'C. difficile-assoziierte Diarrhoe (Prävention)', 'C. difficile-Associated Diarrhea Prevention', 'C. difficile, CDI, CDAD, Krankenhausdiarrhoe, Clostridioides', 'C. difficile, CDI, CDAD, hospital diarrhea', 'Verdauung', 'Infektions-Prävention', 'lacticaseibacillus-casei, lactobacillus-acidophilus', '⭐ L. acidophilus + L. casei KOMBINATION (Bio-K+)', '-', '-', '⭐⭐⭐ STÄRKSTE EVIDENZ! Meta-Analyse Wu 2013: L. acidophilus + L. casei → RR 0,05 (95% CI 0,01-0,36)! Bio-K+ 10-Jahres-Daten: CDI von 18,0 auf 2,3/10.000 Patiententage.', 'STRONGEST evidence! L. acidophilus + L. casei combination: RR 0.05 (95% reduction).', 'Bei CDI-Symptomen sofort Arzt', '⭐ Bio-K+ (L. acidophilus + L. casei + L. rhamnosus) ≥10¹⁰ CFU/Tag während AB.'),
  ('obstipation-shirota', 'Obstipation / Verstopfung', 'Constipation', 'Verstopfung, Obstipation, Darmträgheit, langsamer Transit', 'constipation, slow transit, bowel regularity', 'Verdauung', 'Stuhlregulierung', 'lacticaseibacillus-casei', 'L. casei Shirota (Yakult)', '-', '-', '✅ MODERATE EVIDENZ! Shirota: Kolontransitzeit von 95,6h auf 76,5h (p=0,05). 89% Verbesserung vs. 56% Placebo. Defäkationsfrequenz von 4,81 auf 7,81/Woche.', 'Moderate evidence. Shirota reduces colon transit time and improves bowel frequency.', 'Bei chronischer Obstipation Arzt', 'Yakult (Shirota 6,5×10⁹ CFU/Flasche) täglich.'),
  ('blasenkrebs-shirota', 'Blasenkrebs (Rezidiv-Prophylaxe, Adjuvans)', 'Bladder Cancer Recurrence Prevention', 'Blasenkrebs, TUR, Rezidiv, Harnblasenkrebs', 'bladder cancer, TUR, recurrence prevention', 'Onkologie', 'Adjuvante Therapie', 'lacticaseibacillus-casei', '⭐ L. casei Shirota (EINZIGARTIGE Evidenz!)', '-', '-', '⭐ EINZIGARTIGE EVIDENZ für Probiotikum! Naito 2008 (n=207): Epirubicin + Shirota: 3-Jahres-Rezidivfreiheit 74,6% vs. 59,9% (p=0,0234). BLP 1992: Rezidivfreies Intervall 1,8× verlängert.', 'UNIQUE evidence for bladder cancer. Shirota + epirubicin significantly reduces recurrence.', 'Urologe für Behandlungsplan', '⭐ Shirota 6,5×10⁹ CFU/Tag als Adjuvans nach TUR. NUR in Kombination mit Urologie!'),
  ('ibs-plantarum-299v', '⭐ Reizdarmsyndrom (IBS) - L. plantarum 299v', 'Irritable Bowel Syndrome - L. plantarum 299v', 'Reizdarm, IBS, Colon irritabile, Bauchschmerzen, Blähungen', 'IBS, irritable bowel, abdominal pain, bloating', 'Verdauung', 'Funktionelle Störungen', 'lactiplantibacillus-plantarum', '⭐ L. plantarum 299v (DGVS Grad B empfohlen!)', '-', '-', '⭐⭐⭐ EINZIGES PROBIOTIKUM MIT DGVS-EMPFEHLUNG! Ducrotté 2012 (n=214): 78,1% vs. 8,1% bewerteten Wirkung als gut/exzellent. Bauchschmerz -45,2% vs. -23,3%. Niedzielin 2001: 100% vs. 55% Schmerzauflösung. NNT ~5-7.', 'ONLY probiotic with DGVS guideline recommendation for IBS! Grade B. Meta-analysis: RR=4.6 for abdominal pain relief.', 'Bei Warnsymptomen (Blut, Gewichtsverlust)', '⭐ 299v (DSM 9843) 10¹⁰ CFU/Tag, minimum 4 Wochen. DGVS S3-Leitlinie 2021.'),
  ('flatulenz-plantarum', 'Blähungen / Flatulenz', 'Bloating / Flatulence', 'Blähungen, Flatulenz, aufgeblähter Bauch, Gas', 'bloating, flatulence, gas, distension', 'Verdauung', 'Funktionelle Störungen', 'lactiplantibacillus-plantarum', 'L. plantarum 299v', '-', '-', '✅ POSITIVE EVIDENZ! Nobaek 2000: Signifikante Flatulenz-Reduktion vs. Placebo. ⚠️ ABER: EFSA Health Claim ID 902 für Flatulenz-Reduktion ABGELEHNT.', 'Positive evidence from RCTs. EFSA health claim rejected despite clinical data.', 'Bei persistierenden Beschwerden', '299v 10¹⁰ CFU/Tag.'),
  ('eisenmangel-plantarum', 'Eisenmangel / Eisenresorption', 'Iron Deficiency / Iron Absorption', 'Eisenmangel, Anämie, Eisenaufnahme, Müdigkeit', 'iron deficiency, anemia, iron absorption, fatigue', 'Mikronährstoffe', 'Mineralstoff-Mangel', 'lactiplantibacillus-plantarum', '⭐ L. plantarum 299v', '-', '-', '⭐ STARKE EVIDENZ für 299v! Hoppe 2015: 28,6% vs. 18,5% Absorption (p<0,028). Bering 2006: 80% höhere Absorption aus Phytat-reicher Mahlzeit. Schwangere: Eisenmangel 59% vs. 78%, Anämie 7,4% vs. 21%.', 'Strong evidence for 299v improving iron absorption, especially from plant-based foods.', 'Bei schwerem Eisenmangel', '⭐ 299v als Adjuvans zu Eisen-Supplementierung. ⚠️ EFSA Health Claim für Eisen ABGELEHNT.'),
  ('autismus-ps128', 'Autismus-Spektrum-Störung (ASD) - PS128', 'Autism Spectrum Disorder - PS128', 'Autismus, ASD, Verhaltensauffälligkeiten, Oppositionsverhalten', 'autism, ASD, behavioral problems, opposition', 'Neurologie', 'Entwicklungsstörungen', 'lactiplantibacillus-plantarum', '⭐ L. plantarum PS128 (Psychobiotikum)', '-', '-', '✅ MODERATE EVIDENZ! Liu 2019 (n=71): Verbesserung Opposition/Trotzverhalten bei 7-12-Jährigen. Wu 2021 (n=131): CGI-Verbesserung. Stärkere Effekte bei jüngeren Kindern. Mechanismus: Dopamin/Serotonin-Modulation.', 'Moderate evidence for PS128 in autism. Improves oppositional behavior, especially in younger children.', 'Immer mit Kinderpsychiater', 'PS128 3×10¹⁰ CFU/Tag, 4 Wochen - 4 Monate. Ab 2,5 Jahren in Studien.'),
  ('stress-dr7', 'Stress und Angst - DR7', 'Stress and Anxiety - DR7', 'Stress, Angst, Anspannung, kognitive Funktion', 'stress, anxiety, cognitive function', 'Psyche', 'Stressbewältigung', 'lactiplantibacillus-plantarum', 'L. plantarum DR7', '-', '-', '✅ POSITIVE RCT! Chong 2019 (n=111, 12 Wochen): Signifikante Reduktion von Stress (p=0,024) und Angst (p=0,001). Bei >30-Jährigen: Verbesserung von Aufmerksamkeit und emotionaler Kognition. Plasma-Cortisol signifikant reduziert.', 'Positive RCT evidence for DR7 reducing stress and anxiety in adults.', 'Bei schweren Angststörungen', 'DR7 10⁹ CFU/Tag, 12 Wochen. KABP® Mindbiome.'),
  ('cholesterin-cect', 'Hypercholesterinämie - CECT', 'Hypercholesterolemia - CECT', 'Cholesterin, LDL, Hypercholesterinämie, Blutfette', 'cholesterol, LDL, hypercholesterolemia', 'Herz-Kreislauf', 'Lipidstoffwechsel', 'lactiplantibacillus-plantarum', 'L. plantarum CECT 7527/7528/7529', '-', '-', '✅ POSITIVE RCT! Fuentes 2013 (n=60, 12 Wochen): TC -13,6%, LDL-C -17,6%, oxLDL -15,6% bei hohen Ausgangswerten. Mechanismus: Gallensalz-Hydrolase, Cholesterin-Assimilation.', 'Positive evidence for CECT strains reducing cholesterol in hypercholesterolemic patients.', 'Bei schwerer Hypercholesterinämie', 'CECT 7527/7528/7529 (1:1:1) 1,2×10⁹ CFU/Tag. AB-LIFE®.'),
  ('influenza-kb290', 'Influenza-Prävention - KB290', 'Influenza Prevention - KB290', 'Grippe, Influenza, Erkältung, Immunabwehr', 'flu, influenza, cold, immune defense', 'Immunsystem', 'Infektions-Prävention', 'levilactobacillus-brevis', 'L. brevis KB290', '-', '-', '✅ POSITIVE STUDIEN (Japan)! Waki 2014 (n=1.783 Schulkinder): Influenza-Inzidenz 15,7% vs. 23,9% (p<0,001). Satomi 2021 (n=2.200): + β-Carotin bei <40 Jahren 1,9% vs. 3,9%. NK-Zell-Aktivierung bestätigt.', 'Positive open-label and RCT evidence for KB290 reducing influenza incidence in Japan.', 'Bei Grippe sofort Arzt', 'KB290 ~6×10⁹ CFU/Tag. ⚠️ NUR japanische Studien, keine EU-Leitlinienempfehlung.'),
  ('mundgesundheit-cd2', 'Gingivitis / Parodontitis - CD2', 'Gingivitis / Periodontitis - CD2', 'Zahnfleischentzündung, Gingivitis, Parodontitis, Mundgesundheit', 'gingivitis, periodontitis, gum disease, oral health', 'Mundgesundheit', 'Zahnfleischerkrankungen', 'levilactobacillus-brevis', 'L. brevis CD2 (Inersan®)', '-', '-', '✅ POSITIVE RCTs! Staab 2015 (n=34): Verzögerte Gingivitis-Entwicklung, reduzierte NO-Produktion. Riccia 2007: Reduktion von NOS-Aktivität, IgA, PGE2, MMP bei Parodontitis. Hohe Arginin-Deiminase (ADI)-Aktivität.', 'Positive evidence for CD2 in experimental gingivitis and periodontitis.', 'Bei schwerer Parodontitis Zahnarzt', 'CD2 Lutschtabletten 10⁸-2×10⁹ CFU, 2-4×/Tag. Inersan®.'),
  ('paediatrischer-ibs', 'Pädiatrischer IBS (Kinder-Reizdarm)', 'Pediatric IBS', 'Kinder Reizdarm, IBS Kinder, Bauchschmerzen Kinder, funktionelle Bauchschmerzen', 'pediatric IBS, children abdominal pain, functional abdominal pain', 'Verdauung', 'Pädiatrie', '⭐ calciumbutyrat', '⭐ 1. Calciumbutyrat 500 mg + Zink + Vitamin D (RCT: 73% Erfolg!)', '-', '-', '⭐⭐ BESTE EVIDENZ! RCT Cristofori 2025 (n=51, 4-17 Jahre): Calciumbutyrat 500 mg + Zink + Vitamin D über 8 Wochen → 73% Therapieerfolg (≥50% VAS-Reduktion) vs. 3,8% Placebo (p<0,0001). NNT=2!', 'RCT: 73% success rate with calcium butyrate + zinc + vitamin D in pediatric IBS.', 'Ja (Arzt-Pflicht bei Kindern)', 'Pädiatrische Diagnostik erforderlich'),
  ('nafld-masld', 'NAFLD / MASLD (Fettleber)', 'NAFLD/MASLD', 'Fettleber, NAFLD, MASLD, Lebersteatose, nicht-alkoholische Fettleber', 'fatty liver, NAFLD, MASLD, hepatic steatosis', 'Metabolismus', 'Leber', 'calciumbutyrat, natriumbutyrat', '1. Calciumbutyrat 500 mg/Tag (oder Natriumbutyrat)', '-', '-', '⭐ RCT (n=50): Calciumbutyrat 500 mg/Tag über 3 Monate → signifikante Verbesserung des Fettleber-Index. Keine Nebenwirkungen. Vergleichsstudie (n=181): Kein Unterschied zwischen Ca- und Na-Butyrat im primären Endpunkt.', 'RCT: Calcium butyrate 500 mg/day improved fatty liver index.', 'Ja (NAFLD ist Arzt-Pflicht)', 'Leberwerte, Ultraschall, FibroScan'),
  ('hypertonie-butyrat', 'Butyrat bei Hypertonie (natriumfrei)', 'Butyrate for Hypertension', 'Bluthochdruck Butyrat, Hypertonie natriumfrei, salzfrei', 'hypertension butyrate, sodium-free butyrate', 'Herz-Kreislauf', 'Hypertonie', '⭐ calciumbutyrat, calcium-magnesium-butyrat', '⭐ Calciumbutyrat oder Ca-Mg-Butyrat (NATRIUMFREI!)', '❌ natriumbutyrat', '-', '⚠️ WARNUNG: Studie zeigt Blutdruckerhöhung durch Butyrat möglich (+10 mmHg systolisch)! Widerspricht Tierstudien. Bei Hypertonie: Natriumbutyrat vermeiden (Natriumbelastung), Ca- oder Mg-Butyrat bevorzugen, engmaschige RR-Kontrolle!', 'WARNING: Oral butyrate may INCREASE blood pressure. Use sodium-free forms, monitor BP closely.', 'Ja (Hypertonie ist Arzt-Pflicht)', 'Regelmäßige Blutdruckkontrolle!'),
  ('niereninsuffizienz-butyrat', 'Butyrat bei Niereninsuffizienz', 'Butyrate in Kidney Disease', 'Niereninsuffizienz Butyrat, CKD Butyrat, Niere', 'kidney disease butyrate, CKD butyrate, renal', 'Niere', 'Niereninsuffizienz', '⭐ calciumbutyrat (mit Vorsicht)', '⭐ Calciumbutyrat bevorzugt (natriumarm, phosphatarm)', '❌ natriumbutyrat (Na-Belastung), ⚠️ magnesiumbutyrat (Mg-Akkumulation)', '-', '⚠️ Bei Niereninsuffizienz: Natriumbutyrat vermeiden (Na-Akkumulation). Magnesiumbutyrat mit Vorsicht (Mg-Akkumulation bei GFR<30). Calciumbutyrat bevorzugt, aber Ca-Spiegel überwachen.', 'Use calcium butyrate (sodium-free, phosphate-low). Avoid Mg-butyrate if GFR<30.', 'Ja (CKD ist Arzt-Pflicht)', 'Elektrolyte, Nierenfunktion überwachen'),
  ('darmgesundheit-butyrat', 'Darmgesundheit / Butyrat-Produktion', 'Gut Health / Butyrate', 'Darm, Butyrat, Buttersäure, Colongesundheit, Darmschleimhaut, SCFA', 'gut health, butyrate, colon health, SCFA, intestinal barrier', 'Verdauung', 'Darmgesundheit', 'resistente-staerke-typ2, resistente-staerke-typ3', '1. ✅✅✅ RS2 (Kartoffelstärke) = HÖCHSTE Butyrat-Produktion!; 2. RS3', '-', '-', '✅✅✅ RS produziert 2x MEHR BUTYRAT als andere Ballaststoffe! Kartoffelstärke (RS2): +50% fäkales Butyrat. Butyrat = Hauptenergequelle für Kolonozyten.', '✅✅✅ RS produces 2x MORE BUTYRATE than other fibers!', 'Bei anhaltenden Beschwerden ja', 'Bei chronischen Darmbeschwerden Arzt aufsuchen'),
  ('ibs-fodmap', 'IBS / Reizdarmsyndrom / FODMAP-sensibel', 'IBS / FODMAP Sensitivity', 'IBS, Reizdarm, Reizdarmsyndrom, FODMAP, Blähungen, Durchfall, Verstopfung', 'IBS, irritable bowel syndrome, FODMAP, bloating, digestive issues', 'Verdauung', 'IBS/Reizdarm', 'resistente-staerke-typ4, resistentes-maltodextrin', '1. ✅✅✅ RS4 (Fibersym) = LOW-FODMAP ZERTIFIZIERT!; 2. ✅✅ Nutriose (LOW-FODMAP)', 'inulin, oligofructose (HIGH-FODMAP!)', 'inulin, oligofructose', '✅✅✅ RS4 (Fibersym®) ist der EINZIGE Ballaststoff mit LOW-FODMAP-Zertifizierung (Monash)! Nutriose® ebenfalls LOW-FODMAP. NIEMALS Inulin/FOS bei IBS!', '✅✅✅ RS4 (Fibersym®) is the ONLY LOW-FODMAP certified fiber! NEVER use inulin/FOS for IBS!', 'Ja bei Diagnosestellung', 'IBS-Diagnose durch Arzt wichtig'),
  ('ballaststoff-anreicherung', 'Ballaststoff-Anreicherung / Getränke', 'Fiber Enrichment', 'Ballaststoff, Fiber, Getränk, löslich, Supplement', 'fiber, fiber supplement, soluble fiber, beverage', 'Ernährung', 'Ballaststoffe', 'resistentes-maltodextrin', '1. ✅✅✅ Resistentes Maltodextrin = EINZIGER LÖSLICHER RS!', '-', '-', '✅✅✅ Resistentes Maltodextrin (Fibersol-2, Nutriose, Promitor) ist der EINZIGE lösliche resistente Ballaststoff! Klar in Lösung, geschmacksneutral, hitzestabil. BESTE Verträglichkeit (65g/d)!', '✅✅✅ Resistant Maltodextrin is the ONLY soluble RS! Best tolerance (65g/day)!', 'Nein', '-'),
  ('hoher-cholesterinspiegel', 'Hoher Cholesterinspiegel', 'High Cholesterol', 'Cholesterin, LDL, Hypercholesterinämie, Blutfette', 'cholesterol, LDL, hypercholesterolemia, lipids', 'Herz-Kreislauf', 'Lipide', '⭐ hafer-beta-glucan, gerste-beta-glucan, pektin', '⭐ 1. Hafer-Beta-Glucan 3g/Tag (EFSA Art. 14 Claim!). 2. Pektin 6g/Tag.', '-', '-', '⭐⭐ EFSA ARTIKEL 14 CLAIMS! Hafer/Gerste-Beta-Glucan: 3g/Tag. Pektin: 6g/Tag. Meta-Analysen: LDL -0,25 mmol/L (~6%).', 'EFSA Article 14 Claims for oat/barley beta-glucan (3g/day) and pectin (6g/day).', 'Bei stark erhöhtem LDL', 'Statine oft zusätzlich nötig'),
