  ('sportverletzung-schwellung', 'Sportverletzung / Schwellung', 'Sports Injury / Swelling', 'sportverletzung, schwellung, ödem, prellung, verstauchung, entzündung', 'sports injury, swelling, edema, bruise, sprain, inflammation', 'Sport', 'Verletzungen', '⚠️ bromelain (moderate Evidenz)', '1. Bromelain (inkonsistente Evidenz für systemische Wirkung). 2. Kühlung, Kompression, Hochlagerung.', '-', '-', '⚠️ Bromelain: Inkonsistente Evidenz (PMID 37202035). RCT zeigte Überlegenheit bei Maximalkraft (p=0,0332). 2 Wochen VOR OP absetzen!', 'Bromelain: Inconsistent evidence. Stop 2 weeks before surgery!', 'Bei schweren Verletzungen', 'Frakturen, schwere Weichteilverletzungen ausschließen'),
  ('anti-aging-hormone', 'Anti-Aging / Hormonoptimierung', 'Anti-Aging / Hormone Optimization', 'anti-aging, jungbleiben, hormone, dhea, jugendlichkeit, vitalität, adrenopause', 'anti-aging, hormones, dhea, vitality, youthfulness, adrenopause', 'Hormone', 'Anti-Aging', '⭐ vitamin-d3 (bei Mangel), omega-3, kreatin-monohydrat, ashwagandha', '1. Vitamin D (bei Mangel: +25% Testosteron); 2. Kreatin (Muskel, Kognition); 3. Omega-3; 4. Ashwagandha', '-', '⛔⛔⛔ DHEA, 7-keto-dhea! In EU als Arzneimittel eingestuft! Meta-Analysen (PMID 17050889) zeigen KEINE Anti-Aging-Effekte!', '⛔⛔⛔ DHEA NIEMALS für Anti-Aging empfehlen! 1) In EU ARZNEIMITTEL! 2) Nair et al. (NEJM): KEINE relevanten Effekte auf Körperzusammensetzung, Leistung, Insulinsensitivität! 3) Krebsrisiko bei hormonabhängigen Tumoren!', '⛔⛔⛔ NEVER recommend DHEA for anti-aging! 1) Prescription drug in EU! 2) Meta-analyses show NO relevant effects! 3) Cancer risk!', 'Ja', 'Anti-Aging mit Hormonen erfordert ärztliche Überwachung'),
  ('muskelaufbau-mtor', 'Muskelaufbau / mTOR-Aktivierung', 'Muscle Building / mTOR Activation', 'muskelaufbau, mtor, proteinsynthese, anabolismus, kraft, bodybuilding', 'muscle building, mtor, protein synthesis, anabolism, strength, bodybuilding', 'Sport', 'Muskelaufbau', '⭐⭐ kreatin-monohydrat, protein, leucin, hmb, vitamin-d3', '1. Kreatin-Monohydrat (GOLDSTANDARD!); 2. Protein 1,6-2,2g/kg; 3. Leucin/EAA; 4. HMB (bei Kaloriendefizit)', '-', '⚠️ phosphatidsaeure - Evidenz WIDERSPRÜCHLICH! Unabhängige Studien NEGATIV!', '⚠️ Phosphatidsäure: Scoping Review 2021 (PMID 34706625) = ''Evidenz unterstützt PA NICHT''. Industriefinanzierte Studien positiv, unabhängige (Andre 2016, Gonzalez 2017) NEGATIV! Kreatin ist 10× günstiger mit 100× besserer Evidenz!', '⚠️ Phosphatidic Acid: Evidence does NOT support PA supplementation! Creatine is much better evidence-based and cheaper!', 'Nein', '-'),
  ('nebenniereninsuffizienz', 'Nebenniereninsuffizienz / Morbus Addison', 'Adrenal Insufficiency / Addison''s Disease', 'nebenniereninsuffizienz, addison, nebennierenschwäche, kortisol, aldosteron', 'adrenal insufficiency, addison''s disease, cortisol deficiency', 'Hormone', 'Endokrinologie', '⚠️ DHEA nur auf ärztliche Verordnung! Standardtherapie: Hydrocortison, Fludrocortison', '1. Hydrocortison (Standardtherapie); 2. Fludrocortison; 3. DHEA (add-on, moderate Evidenz, NUR auf Rezept!)', '-', '-', '⚠️ DHEA bei Nebenniereninsuffizienz: MODERATE Evidenz (Arlt 2001, PMID 11196420). Verbessert Wohlbefinden, Sexualfunktion. ABER: Keine EMA-Zulassung für diese Indikation! Nur als Rezepturarzneimittel!', '⚠️ DHEA for adrenal insufficiency: MODERATE evidence. Improves wellbeing. BUT: No EMA approval! Prescription only!', '⛔ ZWINGEND', 'Nebenniereninsuffizienz ist eine schwere Erkrankung - Hormonersatz nur unter Endokrinologe!'),
  ('muskelaufbau-pflanzlich', 'Muskelaufbau mit ''pflanzlichen Anabolika''', 'Muscle Building with ''Plant Anabolics''', 'laxogenin, natürliches anabolikum, pflanzliches steroid, muskelaufbau pflanzlich', 'laxogenin, natural anabolic, plant steroid, plant-based muscle building', 'Sport', 'Muskelaufbau', '⭐⭐ kreatin-monohydrat, protein, ecdysteron (hat Humanstudien!)', '1. Kreatin-Monohydrat (GOLDSTANDARD!); 2. Protein; 3. Ecdysteron (PMID 31123801)', '-', '⛔⛔⛔ laxogenin - KEINE Humanstudien! Einzige Tierstudie zeigt MUSKELATROPHIE!', '⛔⛔⛔ LAXOGENIN NIEMALS EMPFEHLEN! 1) KEINE Humanstudien! 2) Tierstudie: MUSKELATROPHIE statt Aufbau! 3) FDA Advisory List - ILLEGAL in USA! 4) ~40% Fälschungsrate! Ecdysteron hat echte Evidenz (PMID 31123801: n=46, signifikante Muskelmasse-Zunahme)!', '⛔⛔⛔ NEVER recommend Laxogenin! NO human studies! Animal study: MUSCLE ATROPHY! Ecdysterone has real evidence!', 'Nein', '-'),
