  ('ibs-allgemein', 'Reizdarmsyndrom (IBS) - alle Subtypen', 'Irritable Bowel Syndrome (IBS)', 'Reizdarm, IBS, Bauchschmerzen, Blähungen, Stuhlunregelmäßigkeiten, Krämpfe', 'IBS, irritable bowel, abdominal pain, bloating, cramps', 'Verdauung', 'Funktionelle Darmerkrankung', 'reizdarm-support, pfefferminzoel, psyllium, phgg', '1. ⭐ Pfefferminzöl (NNT 3-4), 2. Lösliche Ballaststoffe (NNT 7), 3. Stammspezifische Probiotika', '-', 'inulin, fos, oligofructose, weizenkleie', '⚠️ IBS = Ausschlussdiagnose nach Rom-IV! Red Flags → Koloskopie! Calprotectin <50 = IBS wahrscheinlich. ❌ NIEMALS Inulin/FOS (HIGH-FODMAP)!', 'IBS = diagnosis of exclusion. Red flags → colonoscopy! NEVER inulin/FOS!', 'Ja (Rom-IV-Diagnose)', 'Ausschluss IBD, Zöliakie, Kolorektalkarzinom'),
  ('ibs-c', 'IBS-C (Obstipation-prädominant)', 'IBS-C (Constipation-predominant)', 'IBS-C, Reizdarm mit Verstopfung, harter Stuhl, seltener Stuhlgang', 'IBS-C, constipation-predominant, hard stools, infrequent bowel movements', 'Verdauung', 'Funktionelle Darmerkrankung', 'reizdarm-support, psyllium, phgg', '1. ⭐ Psyllium 10-25g/Tag (NNT 7), 2. PHGG (LOW-FODMAP!)', '-', 'unlösliche Ballaststoffe (verschlimmern!)', '⭐ Lösliche Ballaststoffe First-Line bei IBS-C! Psyllium + viel Wasser. ❌ Kleie verschlimmert!', 'Soluble fiber first-line for IBS-C! Bran worsens symptoms!', 'Ja', 'Beckenboden-Dyssynergie ausschließen'),
  ('morbus-crohn', 'Morbus Crohn', 'Crohns Disease', 'Morbus Crohn, Crohn, CED, IBD, Ileitis, Dünndarmentzündung', 'Crohns disease, Crohn, IBD, ileitis', 'Verdauung', 'Chronisch-entzündliche Darmerkrankung', 'ibd-unterstuetzung, vitamin-d3, vitamin-b12', '1. Vitamin D 2000-4000 IE/Tag (60-70% defizient!), 2. B12 bei Ileumbefall', '-', 'probiotika (GETAID negativ!)', '⚠️ Probiotika bei Morbus Crohn NICHT wirksam! GETAID-Studie negativ. ⚠️ Ballaststoffe bei Stenosen KONTRAINDIZIERT!', 'Probiotics NOT effective in Crohns! GETAID trial negative. Fiber contraindicated with strictures!', 'Ja (CED = Arzt-Pflicht)', 'Gastroenterologische Dauerbetreuung'),
  ('pouchitis', 'Pouchitis (nach Proktokolektomie)', 'Pouchitis', 'Pouchitis, J-Pouch, IPAA, nach Kolektomie', 'pouchitis, J-pouch, IPAA, post-colectomy', 'Verdauung', 'Post-OP Komplikation', 'ibd-unterstuetzung, vsl3', '⭐⭐ VSL#3 3,6×10¹² KBE/Tag: Pouchitis-Prophylaxe 15% vs. 100% (p<0,001)!', '-', '-', '⭐⭐ VSL#3 = Goldstandard Pouchitis-Prophylaxe! Gionchetti-Studien: AGA-empfohlen.', 'VSL#3 = gold standard for pouchitis prophylaxis! AGA-recommended.', 'Ja', 'Chirurgische/gastroenterologische Nachsorge'),
  ('methylierung-support', 'Methylierungs-Support / Homocystein-Senkung', 'Methylation Support', 'methylierung, homocystein, mthfr, folat, methionin, epigenetik', 'methylation, homocysteine, MTHFR, folate, methionine, epigenetics', 'Stoffwechsel', 'Methylierung', 'methylfolat, vitamin-b12, same, betain, vitamin-b6', '⭐⭐⭐ 1. Methylfolat (5-MTHF) + B12 (ESSENZIELL als Paar!). 2. Betain (TMG) als alternativer Methyldonor. 3. SAMe (Endprodukt, bei Bedarf). 4. B6 (Transsulfuration).', '⚠️ Folsäure allein bei MTHFR TT weniger effektiv', '-', '⭐⭐⭐ METHYLIERUNGSZYKLUS: Methylfolat + B12 remethylieren Homocystein zu Methionin → SAMe (Methyldonor). Bei MTHFR C677T TT (8-20% Europäer): Methylfolat umgeht defektes Enzym. B12 ist ESSENZIELL – ohne B12 "Methyl-Trap"!', 'Methylfolate + B12 remethylate homocysteine to methionine → SAMe. B12 is ESSENTIAL.', 'Ja (Homocystein)', 'Homocystein >15 µmol/L: Ärztliche Abklärung'),
  ('schwefel-detox', 'Schwefel-Detox / Sulfatierung-Support', 'Sulfur Detox / Sulfation Support', 'schwefel, sulfat, sulfit, sulfitoxidase, phase 2, detox, sult', 'sulfur, sulfate, sulfite, sulfite oxidase, phase 2, detox, SULT', 'Leber', 'Entgiftung', 'molybdaen, msm, nac, taurin', '⭐⭐⭐ 1. Molybdän (Sulfitoxidase-Kofaktor! Sulfit→Sulfat). 2. NAC/Cystein (Schwefel-Aminosäure). 3. MSM (Schwefeldonor, Evidenz begrenzt). 4. Taurin (aus Cystein).', '-', '-', '⭐⭐⭐ SCHWEFEL-PATHWAY: Methionin → Cystein → Sulfit (TOXISCH!) → SULFAT (Molybdän-abhängig!). Sulfat für SULT-Enzyme (Phase 2). Molybdän ist KRITISCHER Kofaktor für Sulfitoxidase!', 'Sulfur pathway: Methionine → Cysteine → Sulfite (toxic!) → Sulfate (molybdenum-dependent!)', 'Nicht routinemäßig', 'Sulfitintoleranz: Keine kontrollierten Studien zu Mo-Supplementierung'),
  ('depression-adjuvans', 'Depression (Adjuvans)', 'Depression (Adjunct)', 'depression, stimmung, antidepressiva, adjuvans, therapieresistent', 'depression, mood, antidepressant, adjunct, treatment-resistant', 'Nervensystem', 'Psyche', 'same, methylfolat, omega-3', '⭐⭐⭐ 1. SAMe (SMD -0,58 vs. Placebo, vergleichbar mit TCA). 2. Methylfolat 15 mg (bei SSRI-Resistenz, PMID: 23212058). 3. Omega-3 (EPA). ⚠️⚠️ SAMe: BIPOLAR KONTRAINDIZIERT!', '⛔⛔ SAMe bei bipolarer Störung! ⚠️ Serotoninerge Interaktionen!', '-', '⚠️⚠️ NUR unter ärztlicher Aufsicht! SAMe: 9/11 Bipolare switchten in Manie! Methylfolat 15 mg nur bei SSRI-Resistenz unter Arzt. Interaktionen mit Antidepressiva beachten!', 'ONLY under medical supervision! SAMe contraindicated in bipolar disorder!', 'Ja (B12, Folat, Hcy)', '⚠️⚠️ Depression = Ärztliche Behandlung! Supplemente nur adjuvant!'),
  ('verdauung-dyspepsie', 'Leichte Verdauungsbeschwerden / Dyspepsie', 'Mild Digestive Complaints / Dyspepsia', 'Verdauungsbeschwerden, Völlegefühl, Blähungen, langsame Verdauung, Appetitmangel, Dyspepsie', 'digestive complaints, bloating, flatulence, slow digestion, loss of appetite, dyspepsia', 'Verdauung', 'Funktionelle Beschwerden', 'loewenzahn-leber-support, artischocke, enzian-bitter', '1. Artischocke (beste Evidenz), 2. Löwenzahn (Traditional Use), 3. Enzian-Bitter', '-', '-', '⭐ Löwenzahn: EMA Traditional Use für Dyspepsie! Bei anhaltenden Beschwerden: organische Ursachen ausschließen.', 'Dandelion: EMA Traditional Use for dyspepsia! For persistent complaints: rule out organic causes.', 'Bei >2 Wochen ohne Besserung', 'Ausschluss Gastritis, Ulkus, H. pylori, Gallensteine'),
  ('dysphagie-ballaststoff', 'Ballaststoff bei Dysphagie/Schluckstörungen', 'Fiber for Dysphagia', 'Dysphagie, Schluckstörungen, Aspirationsrisiko, Senioren, Psyllium-Unverträglichkeit', 'dysphagia, swallowing difficulty, aspiration risk, elderly', 'Verdauung', 'Ballaststoffe', 'phgg, metamucil-alternative', '1. ⭐ PHGG (KEIN Erstickungsrisiko!), 2. Metamucil-Alternative', 'flohsamenschalen (ERSTICKUNGSRISIKO!)', 'methylcellulose (auch Erstickungswarnung bei Dysphagie)', '⭐ PHGG ist die EINZIGE sichere Wahl bei Dysphagie! Psyllium hat 4 dokumentierte Todesfälle. PHGG geliert NICHT.', '⭐ PHGG is the ONLY safe choice for dysphagia! Psyllium has 4 documented deaths. PHGG does NOT gel.', 'Ja - Abklärung der Dysphagie-Ursache', 'Neurologische Erkrankungen, Schlaganfall, Ösophagusstrikturen'),
  ('ibs-blaehungen', 'IBS mit Blähungen bei Psyllium', 'IBS with Bloating on Psyllium', 'Reizdarm, IBS, Blähungen durch Ballaststoffe, Psyllium-Unverträglichkeit, Gasbildung', 'IBS, irritable bowel, bloating, fiber intolerance, gas', 'Verdauung', 'IBS', 'phgg, methylcellulose, metamucil-alternative', '1. ⭐ PHGG (IBS: NNT=6, LOW-FODMAP), 2. Methylcellulose (null Gas!), 3. Metamucil-Alternative', '-', '-', '⭐ PHGG: NNT=6 für IBS. Methylcellulose: 100% nicht fermentierbar = NULL Gas. Kombination möglich.', 'PHGG: NNT=6 for IBS. Methylcellulose: non-fermentable = zero gas.', 'Bei Rom-IV-Kriterien', 'IBS-Diagnose gemäß Rom-IV-Kriterien'),
